package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.Collections;
import java.util.List;

import org.junit.jupiter.api.Test;

class CartTest {

  static class LineItem {}

  @Test
  void testGetBuyerName() throws Exception {
    List<LineItem> lineItems = Collections.emptyList();
    String buyerName = "John Doe";
    String creditCard = "1234-5678-9876-5432";

    // Use reflection to create Cart instance since Cart constructor is not fully visible
    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");
    java.lang.reflect.Constructor<?> constructor = cartClass.getDeclaredConstructor(List.class, String.class, String.class);
    constructor.setAccessible(true);
    Object cart = constructor.newInstance(lineItems, buyerName, creditCard);

    // Invoke getBuyerName method via reflection
    java.lang.reflect.Method getBuyerNameMethod = cartClass.getMethod("getBuyerName");
    String result = (String) getBuyerNameMethod.invoke(cart);

    assertEquals(buyerName, result);
  }
}
